    if (steps.length === 0) {
        const algo = document.getElementById('algoSelect').value;
        if (algo === 'greedy') steps = algoGreedy();
        else if (algo === 'exact') steps = algoExact();
        else steps = algoComplement();
    }
    if (stepIdx < steps.length - 1) {
        stepIdx++;
        applyStep(stepIdx);
        draw();
    }
