function updateTheorems() {
    const n = nodes.length;
    const alpha = indepSet.size;
    const beta = n - alpha; // Gallai: α + β = n → β = n - α
    // ω(Ḡ) = α(G)
    const el = document.getElementById('theoremValues');
    el.innerHTML = `<strong>α(G) = ${alpha}</strong>, β(G) = ${beta}, n = ${n} → α + β = ${alpha} + ${beta} = ${n} ✓<br>` +
