function updateStats() {
    const n = nodes.length, m = edges.length;
    document.getElementById('statNodes').textContent = n;
    document.getElementById('statEdges').textContent = m;
    document.getElementById('statDensity').textContent = n > 1 ? (2*m/(n*(n-1))).toFixed(2) : '0';
