/* ── Drawing ── */
function draw() {
    const W = canvas.width, H = canvas.height;
    ctx.clearRect(0, 0, W, H);

    // edges
    for (const [u,v] of edges) {
        const nu = nodes[u], nv = nodes[v];
        const uIn = indepSet.has(u), vIn = indepSet.has(v);
        const uElim = eliminated.has(u), vElim = eliminated.has(v);
