    gap: 10px;
    padding: 0 20px 20px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 16px;
    text-decoration: none;
    color: var(--text);
}

.sidebar-logo span { font-size: 1.5rem; }
.sidebar-logo h2 { font-size: 1.1rem; font-weight: 700; }
.sidebar-logo small { font-size: 0.75rem; color: var(--text-muted); display: block; }

.sidebar-section {
    padding: 0 12px;
    margin-bottom: 8px;
}

.sidebar-section-title {
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--text-subtle);
    padding: 8px 8px 4px;
    font-weight: 600;
}

.sidebar-link {
    display: block;
    padding: 6px 12px;
    color: var(--text-muted);
    text-decoration: none;
    font-size: 0.9rem;
    border-radius: 6px;
    transition: all 0.15s;
}

.sidebar-link:hover {
    color: var(--text);
    background: var(--surface-hover);
}

.sidebar-link.active {
    color: var(--accent);
    background: rgba(88, 166, 255, 0.1);
    font-weight: 500;
}

.sidebar-link .icon { margin-right: 8px; font-size: 0.85rem; }

/* ---- Main Content ---- */
.main {
    margin-left: var(--sidebar-width);
    min-height: 100vh;
}

.content {
    max-width: 900px;
    margin: 0 auto;
    padding: 48px 40px 80px;
}

/* ---- Typography ---- */
h1 {
    font-size: 2.25rem;
    font-weight: 700;
    margin-bottom: 8px;
    line-height: 1.3;
}

h1 .subtitle {
    display: block;
    font-size: 1.1rem;
    color: var(--text-muted);
    font-weight: 400;
    margin-top: 8px;
}

h2 {
    font-size: 1.6rem;
    font-weight: 600;
    margin-top: 48px;
    margin-bottom: 16px;
    padding-bottom: 8px;
    border-bottom: 1px solid var(--border);
}

h3 {
    font-size: 1.2rem;
    font-weight: 600;
    margin-top: 32px;
    margin-bottom: 12px;
    color: var(--accent);
}

h4 {
    font-size: 1rem;
    font-weight: 600;
    margin-top: 24px;
    margin-bottom: 8px;
}

p {
    margin-bottom: 16px;
    color: var(--text);
}

p.muted { color: var(--text-muted); }

/* ---- Code ---- */
code {
    background: var(--surface);
    padding: 2px 6px;
    border-radius: 4px;
    font-size: 0.88em;
    border: 1px solid var(--border);
    font-family: 'SF Mono', 'Fira Code', 'Cascadia Code', monospace;
}

pre {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 16px 20px;
    overflow-x: auto;
    margin: 16px 0 24px;
    line-height: 1.5;
}

pre code {
    background: none;
    border: none;
    padding: 0;
    font-size: 0.88rem;
}

/* ---- Tables ---- */
table {
    width: 100%;
    border-collapse: collapse;
    margin: 16px 0 24px;
}

th, td {
    padding: 10px 14px;
    border: 1px solid var(--border);
    text-align: left;
    font-size: 0.92rem;
}

th {
    background: var(--surface);
    font-weight: 600;
    white-space: nowrap;
}

tr:hover { background: rgba(88, 166, 255, 0.03); }

/* ---- Cards ---- */
.card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 16px;
    margin: 16px 0 24px;
}

.card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 20px;
    transition: border-color 0.2s;
}

.card:hover { border-color: var(--accent); }

